function solve(code, businessLine, isActive) {
    const validBusinessLines = new Set(["electronics", "grocery", "pharmacy", "restaurant"]);
    const businessLineOrder = { "electronics": 0, "grocery": 1, "pharmacy": 2, "restaurant": 3 };
    const validCoupons = [];

    for (let i = 0; i < code.length; i++) {
        const currentCode = code[i];
        const currentBusinessLine = businessLine[i];
        const currentIsActive = isActive[i];

        // Check if code is valid (non-empty and only alphanumeric + underscore)
        let isCodeValid = currentCode.length > 0;
        if (isCodeValid) {
            for (const char of currentCode) {
                if (!(/[a-zA-Z0-9_]/.test(char))) {
                    isCodeValid = false;
                    break;
                }
            }
        }

        // Check if business line is valid
        const isBusinessLineValid = validBusinessLines.has(currentBusinessLine);

        // Check if coupon is active
        const isActiveValid = currentIsActive === true;

        if (isCodeValid && isBusinessLineValid && isActiveValid) {
            validCoupons.push({
                code: currentCode,
                businessLine: currentBusinessLine
            });
        }
    }

    // Sort the valid coupons
    validCoupons.sort((a, b) => {
        const orderA = businessLineOrder[a.businessLine];
        const orderB = businessLineOrder[b.businessLine];
        if (orderA !== orderB) {
            return orderA - orderB;
        } else {
            return a.code.localeCompare(b.code);
        }
    });

    // Extract the codes in order
    return validCoupons.map(coupon => coupon.code);
}

