fun solve(code: Array<String>, businessLine: Array<String>, isActive: Array<Boolean>): Array<String> {
    val validBusinessLines = setOf("electronics", "grocery", "pharmacy", "restaurant")
    val businessLineOrder = mapOf("electronics" to 0, "grocery" to 1, "pharmacy" to 2, "restaurant" to 3)
    val validCoupons = mutableListOf<Pair<String, String>>()

    for (i in code.indices) {
        val currentCode = code[i]
        val currentBusinessLine = businessLine[i]
        val currentIsActive = isActive[i]

        // Check if code is valid (non-empty and only alphanumeric + underscore)
        val isCodeValid = currentCode.isNotEmpty() && currentCode.all { it.isLetterOrDigit() || it == '_' }

        // Check if business line is valid
        val isBusinessLineValid = currentBusinessLine in validBusinessLines

        // Check if coupon is active
        val isActiveValid = currentIsActive

        if (isCodeValid && isBusinessLineValid && isActiveValid) {
            validCoupons.add(currentCode to currentBusinessLine)
        }
    }

    // Sort the valid coupons
    validCoupons.sortWith(compareBy<Pair<String, String>> { (_, businessLine) -> businessLineOrder[businessLine] }
        .thenBy { (code, _) -> code })

    // Extract the codes in order
    return validCoupons.map { it.first }.toTypedArray()
}
